changeSet.sql:
ALTER TABLE t1.scratch ENABLE ROW LEVEL SECURITY;
ALTER TABLE t1.scratch FORCE ROW LEVEL SECURITY;

-- GUC name: nexus.t1_tenant (NOT nexus.tenant — avoid conflating T1 and T2 contexts).
-- missing_ok=true: unset GUC returns NULL, which != any tenant_id -> fail-closed.
-- cmd=ALL: covers SELECT, INSERT, UPDATE, DELETE.
CREATE POLICY tenant_isolation ON t1.scratch
    USING      (tenant_id = current_setting('nexus.t1_tenant', true))
    WITH CHECK (tenant_id = current_setting('nexus.t1_tenant', true));

changeSet.rollback:
DROP POLICY IF EXISTS tenant_isolation ON t1.scratch;
ALTER TABLE t1.scratch NO FORCE ROW LEVEL SECURITY;
ALTER TABLE t1.scratch DISABLE ROW LEVEL SECURITY;

changeSet.sql:
ALTER TABLE t1.scratch
    ADD COLUMN fts_vector TSVECTOR GENERATED ALWAYS AS (
        setweight(to_tsvector('english', coalesce(content, '')), 'B') ||
        setweight(to_tsvector('simple',  coalesce(tags,    '')), 'C')
    ) STORED;

-- GIN index: accelerates @@ operator queries
CREATE INDEX idx_scratch_fts ON t1.scratch USING GIN (fts_vector);

DO $$
BEGIN
    IF EXISTS (SELECT 1 FROM pg_roles WHERE rolname = 'nexus_svc') THEN
        EXECUTE 'GRANT USAGE ON SCHEMA t1 TO nexus_svc';
        EXECUTE 'GRANT SELECT, INSERT, UPDATE, DELETE ON t1.scratch TO nexus_svc';
        EXECUTE 'ALTER ROLE nexus_svc SET search_path TO nexus, t1, public';
        RAISE NOTICE 'Granted t1.scratch privileges to nexus_svc';
    ELSE
        RAISE NOTICE 'nexus_svc role not found; skipping grants (create role before first run)';
    END IF;
END
$$;
